INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นคือธุรกิจ ซื้อเพื่อเป็นเจ้าของ');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', '1. อนาคตระยะยาวของบริษัท. Competitive Capable');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', '2. คุณภาพผู้บริหาร');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', '3. ความแข็งแกร่งทางการเงิน');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', '4. ประวัติการจ่ายปันผล ROE > 20%');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', '5. นโยบายจ่ายปันผลในปัจจุบัน');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', '6. PE ควรน้อยกว่าอัตราการเติบโตของกำไร เฉลี่ย 3-5 ปี');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นโตช้า PE 5-10 หวังปันผล');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นแข็งแกร่ง PE 10-15 โต 10-20% หวังปันผล ขาลงไม่รุนแรง (ขายเมื่อ PE ฉีกมากเกินไป แล้วซื้อคืนภายหลัง)');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นโตเร็ว PE 15-20 โต 20+% หวัง Capital Gain หรือหุ้น 10 เด้ง (ขายเมื่อเริ่มชะลอตัว)');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นฟื้นตัว บริษัทฟื้นจากความตาย ตัดแขนขา พลิกฟื้นกิจการ มักจะเด้งกลับรุนแรง (เริ่มขายเมื่อมันฟื้นตัวแล้ว ให้จัดกลุ่มหุ้นใหม่)');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นทรัพย์สินมาก. ราคาหุ้นต่ำกว่าทรัพยสินที่มี ต้องถือยาวนาน แล้วรอให้มันเจ๊ง');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'หุ้นวัฐจักร (เริ่มขายเมื่อโรงงานเริ่มเต็มกำลังการผลิต หรือเริ่มใช้เงินเพื่อขยายกำลังการผลิต หรือสินค้าคงคลังกำลังเพิ่มขึ้น)');
INSERT INTO knowledge_base (category, title, content) VALUES ('General', 'Note', 'The Intelligent Investor');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', '1. อนาคตระยะยาวของบริษัท');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', '2. ความสามารถทำกำไรอย่างยั่งยืน');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'ซื้อกิจการบ่อยๆ มักขายทิ้งเพราะซื้อมาแพงเกินไป');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'ก่อหนี้และเพิ่มทุนตลอดเวลา');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'บริษัทมีรายได้จากลูกค้ารายเดียว');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'มีความได้เปรียบเชิงการแข่งขันแข็งแกร่ง (Brand, Economies of scale, สูตรลับ, ความหายาก)');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'บริษัทเป็นนักวิ่งมาราธอน');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'บริษัทใช้งบ R&D เหมาะสม');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'Five Force ดี สินค้าขึ้นราคาได้');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', '2. คุณภาพของผู้บริหาร');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'ค่าตอบแทนไม่สูงจนเกินไป');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'พวกเขาเป็นผู้บริหาร หรือคนขายฝัน');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', '3. ความแข็งแกร่งทางการเงิน');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'การเติบโตของผลกำไรสม่ำเสมอ');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', 'หนี้สินระยะยาวต่ำกว่า 50% ของเงินลงทุน ดอกเบี้ยคงที่ หรือลอยตัว');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', '4. ประวัติการจ่ายปันผล');
INSERT INTO knowledge_base (category, title, content) VALUES ('การวิเคราะห์หุ้นสามัญสำหรับนักลงทุนทั่วไป', 'Note', '5. นโยบายการจ่ายปันผล');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'ขนาดของบริษัทใหญ่เพียงพอ (ทรัพย์สิน, ยอดขาย)');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'ฐานะทางการเงินแข็งแกร่งเพียงพอ (ทรัพย์สินหมุนเวียนสูงกว่าหนี้สินหมุนเวียน)');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'เสถียรภาพของผลกำไร (ในช่วงสิบปีที่ผ่านมา)');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'ประวัติการจ่ายปันผลต่อเนื่อง');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'การเติบโตของผลกำไร');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'P/E ไม่สูงเกินไป (15 เท่าของผลกำไรเฉลี่ยในช่วงสามปีที่ผ่านมา)');
INSERT INTO knowledge_base (category, title, content) VALUES ('กลยุทธ์การลงทุนเชิงรับ', 'Note', 'P/B ไม่สูงเกินไป (ไม่เกิน 1¹/2 ของ Book per share ยกเว้น P/E ต่ำ >>15*1.5 = 22.5)');
INSERT INTO knowledge_base (category, title, content) VALUES ('การคิด PE จากดอกเบี้ย', 'Note', '*ดอกเบี้ยหุ้นกู้อายุ 10ปี เครดิต AA = 4.4% >> 100/4.6 จะได้ PE สูงสุด 21.7 เท่า คิดส่วนลด 20% เท่ากับ 17.3 เท่า**');
INSERT INTO knowledge_base (category, title, content) VALUES ('การเลือกหุ้นสำหรับนักลงทุนเชิงรุก', 'Note', 'การเลือกหุ้น PE ต่ำ มีกฎเกณฑ์เพิ่มดังนี้');
INSERT INTO knowledge_base (category, title, content) VALUES ('การเลือกหุ้นสำหรับนักลงทุนเชิงรุก', 'Note', 'ฐานะทางการเงิน : สินทรัพย์หมุนเวียน 150% ของ หนี้สินหมุนเวียน. หนี้สินไม่เกิน 110% ของสินทรัพย์หมุนเวียน');
INSERT INTO knowledge_base (category, title, content) VALUES ('การเลือกหุ้นสำหรับนักลงทุนเชิงรุก', 'Note', 'เสถียรภาพของกำไร : ไม่มีผลขาดทุนในช่วง 5 ปีหลังสุด');
INSERT INTO knowledge_base (category, title, content) VALUES ('การเลือกหุ้นสำหรับนักลงทุนเชิงรุก', 'Note', 'ประวัติการจ่ายผล : มีการจ่ายปันผลในปัจจุบัน');
INSERT INTO knowledge_base (category, title, content) VALUES ('การเลือกหุ้นสำหรับนักลงทุนเชิงรุก', 'Note', 'การเติบโตของกำไร : ผลกำไรสูงกว่าปีก่อนหน้า');
INSERT INTO knowledge_base (category, title, content) VALUES ('การเลือกหุ้นสำหรับนักลงทุนเชิงรุก', 'Note', 'ราคา : ต่ำกว่า 120% ของสินทรัพย์มีตัวตนสุทธิ');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'ความสามารถในการทำกำไร (E/P) เหนือกว่าดอกเบี้ยจ่าย');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'การจัดพอร์ตหุ้นตามวัฏจักรเศรษฐกิจ');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', '1. ช่วงเศรษฐกิจขยายตัว (Expansion) และ การจัดพอร์ตหุ้นในช่วงเศรษฐกิจขยายตัว');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'เป็นช่วงที่เศรษฐกิจเริ่มกลับมาฟื้นตัวหลังจากผ่านช่วงเวลาที่ตกต่ำมา ซึ่งเป็นช่วงเวลาที่เหมาะสมที่สุดสำหรับการลงทุน เพราะไม่ว่าจะลงทุนอะไรก็มักจะกำไรไปหมด ภาคครัวเรือนและภาคเอกชนมีความมั่นใจในระบบเศรษฐกิจมากขึ้น ทำให้ภาคครัวเรือนมีการจับจ่ายใช้สอยมากขึ้น และภาคเอกชนก็กลับมาลงเพิ่มขึ้นทำให้เศรษฐกิจขยายตัว');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'การจัดพอร์ตหุ้นในช่วงเศรษฐกิจขยายตัวนั้น ควรจัดพอร์ตแบบเชิงรุกลงทุนในหุ้นที่ให้อัตราผลตอบแทนสูงถือเงินสดให้น้อยที่สุด เพราะช่วงเวลานี้ถือเป็นช่วงที่น่าลงทุนที่สุดเพราะราคาหุ้นยังไม่อยู่ในจุดที่แพงมาก กิจการลงทุนอะไรก็มักจะได้ผลกำไร ทำให้สามารถสร้างอัตราผลตอบแทนได้สูงและมีความเสี่ยงที่ต่ำ');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', '2.ช่วงเศรษฐกิจรุ่งเรือง (Peak) และ การจัดพอร์ตหุ้นในช่วงเศรษฐกิจรุ่งเรือง');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'เป็นช่วงเวลาที่อยู่ในจุดสูงสุดของระบบเศรษฐกิจ ซึ่งเป็นช่วงที่มีอัตราการจ้างงานสูงที่สุด อัตราการว่างงานต่ำประชาชนมีกำลังการใช้จ่ายที่สูง การจับจ่ายใช้สอยสะพัด ทำให้ภาคการผลิตเริ่มขาดแคลนแรงงานในการผลิต ทำให้ต้องยอมจ้างพนักงานที่มีคุณภาพต่ำและค่าจ้างที่สูงขึ้น ทำให้ต้นทุนในการผลิตสูงขึ้นและผลผลิตคุณภาพต่ำลง เพื่อเพิ่มกำลังการผลิตให้เพียงพอต่อความต้องการของตลาด อัตราเงินเฟ้อสูงก็ปรับตัวสูงขึ้นต่อเนื่องตามลำดับ');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'การจัดพอร์ตหุ้นในช่วงเศรษฐกิจรุ่งเรือง ช่วงนี้จะเป็นช่วงที่หุ้นจะให้อัตราผลตอบแทนที่สูงที่สุด แต่ไม่ใช่ช่วงเวลาที่เหมาะสมสำหรับการซื้อหุ้น เพราะราคาหุ้นส่วนมากจะแพงกันหมดแล้ว แต่ถ้าหากเราได้ซื้อหุ้นจากช่วงเศรษฐกิจขยายตัว หุ้นในพอร์ตก็คงมีกำไรมากพอสมควร ให้ทำการขายหุ้นที่มีความเสี่ยงสูงออกจากพอร์ตทำกำไร เพื่อถือเงินสดให้มากขึ้น เพื่อเตรียมพร้อมสำหรับช่วงเศรษฐกิจถดถอยที่กำลังจะมาถึง');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', '3.ช่วงเศรษฐกิจถดถอย (Contraction) และ การจัดพอร์ตหุ้นในช่วงเศรษฐกิจถดถอย');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'เมื่อผ่านจุดสูงสุดของระบบเศรษฐกิจไปแล้วระบบเศรษฐกิจจะเข้าสู่สภาวะถดถอย ในช่วงนี้จะตัวเลขทางด้านเศรษฐกิจที่เคยปรับตัวขึ้นต่อเนื่องจะค่อยๆปรับตัวลดลง เช่น อัตราการจ้างงานต่ำลง การใช้จ่ายของภาคครัวเรือนต่ำลง ซึ่งเกิดจากหลายปัจจัยเช่น อัตราเงินเฟ้อที่สูงขึ้นทำให้ข้าวของเครื่องใช้มีราคาสูง ส่งผลให้ภาคครัวเรือนไม่มีกำลังซื้อที่เพียงพอ ซึ่งมีผลทำให้ภาคการผลิตขายสินค้าไม่ได้ จึงต้องลดกำลังการผลิตลง และไม่เกิดการจ้างงานเพิ่ม มีผลทำให้เศรษฐกิจถดถอย หากในภาครัฐบาลและภาคเอกชนเตรียมพร้อมรับมือกับช่วงถดถอย การถดถอยจะเป็นแบบค่อยเป็นค่อยไป แต่ถ้าหากไม่มีการเตรียมการจะถดถอยจะรวดเร็วและรุนแรง');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'การจัดพอร์ตหุ้นในช่วงเศรษฐกิจถดถอย ในช่วงนี้ควรเหลือถือเฉพาะหุ้นกลุ่มที่ได้รับผลกระทบน้อยจากการถดถอยของระบบเศรษฐกิจ เช่น หุ้นในกลุ่มที่สินค้าที่มีความจำเป็นต่อการดำเนินชีวิต เช่น อาหาร ยารักษาโรค โรงพยาบาล เป็นต้น และควรเลือกหุ้นที่จ่ายเงินปันผลมาก เพราะการรับเงินปันผลเลยจะช่วยลดความเสี่ยงของพอร์ตลงเพราะเราจะได้รับกระแสเงินสดกลับมาเก็บบ้าง เพราะว่าการลงทุนอะไรในช่วงนี้ของกิจการมักเป็นไปด้วยความยากลำบาก การลงทุนในช่วงเศรษฐกิจถดถอยควรถือเงินสดให้มากกว่าหุ้น');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', '4.ช่วงเศรษฐกิจตกต่ำ (Trough) และ การจัดพอร์ตหุ้นในช่วงเศรษฐกิจตกต่ำ');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'เป็นช่วงตกต่ำที่สุดของวัฏจักรเศรษฐกิจ เป็นภาวะที่มีตัวเลขการว่างงานสูง สินค้าและบริการขายได้ต่ำ เป็นช่วงที่ภาคเอกชนรู้สึกท้อและหมดหวัง เพราะทำอะไรก็มักจะขาดทุนไปหมด ภาคครัวเรือนไม่มั่นใจในการจับจ่ายใช้สอย จึงไม่มีเงินเข้ามาหมุนเวียนในระบบเศรษฐกิจทำให้เศรษฐกิจอยู่ในช่วงที่ตกต่ำที่สุด');
INSERT INTO knowledge_base (category, title, content) VALUES ('Margin of safety', 'Note', 'การจัดพอร์ตหุ้นในช่วงเศรษฐกิจตกต่ำ การลงทุนในช่วงนี้ถือเป็นช่วงเวลาที่เหมาะสมสำหรับการเลือกเก็บและสะสมหุ้น เพราะถือเป็นช่วงที่ราคาหุ้นถูกที่สุด ควรจะเลือกหุ้นที่มีพื้นฐานที่ดี และมีฐานะทางการเงินที่ยังแข็งแรงอยู่ เช่น หุ้นที่เป็นผู้นำในแต่ล่ะอุตสาหกรรมเพราะจะเป็นหุ้นที่สามารถฟื้นตัวได้ดีและเร็ว เพราะมีความสามารถในการแข่งขันสูงกว่าหุ้นขนาดเล็ก เพราะมีต้นทุนการผลิตที่ต่ำกว่า เป็นต้น');